{"version":3,"names":["spaceReg","commaReg","extractLengthList","lengthList","Array","isArray","map","el","String","trim","replace","split"],"sources":["extractLengthList.ts"],"sourcesContent":["import { NumberProp } from './types';\n\nconst spaceReg = /\\s+/;\nconst commaReg = /,/g;\n\nexport default function extractLengthList(\n  lengthList?: readonly NumberProp[] | NumberProp,\n): string[] {\n  if (Array.isArray(lengthList)) {\n    return lengthList.map((el) => String(el));\n  } else if (typeof lengthList === 'number') {\n    return [String(lengthList)];\n  } else if (typeof lengthList === 'string') {\n    return lengthList.trim().replace(commaReg, ' ').split(spaceReg);\n  } else {\n    return [];\n  }\n}\n"],"mappings":"2FAEA,GAAMA,SAAQ,CAAG,KAAjB,CACA,GAAMC,SAAQ,CAAG,IAAjB,CAEe,QAASC,kBAAT,CACbC,UADa,CAEH,CACV,GAAIC,KAAK,CAACC,OAAN,CAAcF,UAAd,CAAJ,CAA+B,CAC7B,MAAOA,WAAU,CAACG,GAAX,CAAe,SAACC,EAAD,QAAQC,OAAM,CAACD,EAAD,CAAd,EAAf,CAAP,CACD,CAFD,IAEO,IAAI,MAAOJ,WAAP,GAAsB,QAA1B,CAAoC,CACzC,MAAO,CAACK,MAAM,CAACL,UAAD,CAAP,CAAP,CACD,CAFM,IAEA,IAAI,MAAOA,WAAP,GAAsB,QAA1B,CAAoC,CACzC,MAAOA,WAAU,CAACM,IAAX,GAAkBC,OAAlB,CAA0BT,QAA1B,CAAoC,GAApC,EAAyCU,KAAzC,CAA+CX,QAA/C,CAAP,CACD,CAFM,IAEA,CACL,MAAO,EAAP,CACD,CACF"}
